INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2231, 213779, 13, 777, '明年中秋但愿再团圆', '今年的中秋或许是我一生中过的最快乐的一次了，自从来了咖啡以后，算算也有好几个年头了，在这里，认识了许多许多的好朋友，记得在千僖年的5.1，经常在这里的一群天天混咖啡的疯子在某个大疯子（菜刀）的牵引下走在了一起，并在一个极其破烂的网吧（蓝色零点网吧）结为兄弟（嘿嘿，有个女的我们误把他当男的了，后经调查发现其乃一女性也）从那天起，这群疯子在经常在一起玩乐，后来，发生了许许多多的事情，大家由于种种原因也就很少在一起了，但是不管如何，每年的中秋虽然无法全部团圆，我们好象尽可能的集中到能集中的在一起博饼，并约定第二年的博饼由当年的状元来组织，今年，由于我一直在外地工作，本无法参加，或许是上帝的安排，一个偶然的机会竟然让我在中秋的时候回厦门了几天，（哈。。爽。。。）去年的状元得主理所当然的组织了博饼，嘿嘿，大家想知道是谁吗？（悄悄告诉大家哦，那个人就是咖啡最狂，鼎鼎大名的菜刀同志）哇！这家伙还真厉害，我恨不得叫老大把位置让给他来当。。。他把在厦门的所有人都集中了，难得的一次聚会就在他的组织下形成了，不过真TNND，在他家这家伙竟然组织大家做起了违法的事情（打麻将）日死，，害我输了100多，，555555我的血汗钱啊！！！那天，说实话，大家都很高兴也很尽兴，在安排博饼以后，前年的状元去年由于其他原因跑台了，奶奶的，想起来就想P他，不过这家伙还算能认识自己的错误，嘿嘿，在博饼之后安排大家去爽了一下（别误会，这次没干违法的事情，安排大家去狠K了一次）哈。。这家伙醉了不过由于高兴大家有都差不多了（哈，我先跑了，俺家那位看俺实在不行了，拉着俺跑路了）虽然这次的安排非常好，但是，我总觉得有那么一些遗憾，原因是少了一个，这么多年了，大家在年龄上都向天马走得更近了，55555老了：）我总希望能有那么一次能够更好的聚会一次，只是由于大家忙的忙，在外地的在外地，一直未能如愿，特别是我们之中的很多同志由于一个个的走进围墙，所以机会也自然少了许多，在这里，我要说的是，不管以前发生过什么，我希望在来年的中秋，我们能够更集中更团结，让我们在一起互相聊聊这些年来的开心，快乐。痛楚，悲伤。。。。。。（哈。。估计有人要跳起来了，今年的状元玫瑰，，嘿嘿。。谁让你带一个杀手来把我们的状元拿走了，555，明年。。嘿嘿。。。你自己看着办）哇！忽然想起，明年的中秋我们又多了一个抱着小宝宝的，，玫瑰，我帮你算好了，明年如果能全部到的话，那么有24个人，哈哈，，惨了你！最后，我衷心的希望我们的友谊能像长城一样，每年的中秋都能集中！（虽然我年年拿不到状元）', '今年的中秋或许是我一生中过的最快乐的一次了，自从来了咖啡以后，算算也有好几个年头了，在这里，认识了许多许多的好朋友，记得在千僖年的5.1，经常在这里的一群天天混咖啡的疯子在某个大疯子（菜刀）的牵引下走在了一起，并在一个极其破烂的网吧（蓝色零点网吧）结为兄弟（嘿嘿，有个女的我们误把他当男的了，后经调查发现其乃一女性也）从那天起，这群疯子在经常在一起玩乐，后来，发生了许许多多的事情，大家由于种种原因也就很少在一起了，但是不管如何，每年的中秋虽然无法全部团圆，我们好象尽可能的集中到能集中的在一起博饼，并约定第二年的博饼由当年的状元来组织，今年，由于我一直在外地工作，本无法参加，或许是上帝的安排，一个偶然的机会竟然让我在中秋的时候回厦门了几天，（哈。。爽。。。）去年的状元得主理所当然的组织了博饼，嘿嘿，大家想知道是谁吗？（悄悄告诉大家哦，那个人就是咖啡最狂，鼎鼎大名的菜刀同志）哇！这家伙还真厉害，我恨不得叫老大把位置让给他来当。。。他把在厦门的所有人都集中了，难得的一次聚会就在他的组织下形成了，不过真TNND，在他家这家伙竟然组织大家做起了违法的事情（打麻将）日死，，害我输了100多，，555555我的血汗钱啊！！！那天，说实话，大家都很高兴也很尽兴，在安排博饼以后，前年的状元去年由于其他原因跑台了，奶奶的，想起来就想P他，不过这家伙还算能认识自己的错误，嘿嘿，在博饼之后安排大家去爽了一下（别误会，这次没干违法的事情，安排大家去狠K了一次）哈。。这家伙醉了不过由于高兴大家有都差不多了（哈，我先跑了，俺家那位看俺实在不行了，拉着俺跑路了）虽然这次的安排非常好，但是，我总觉得有那么一些遗憾，原因是少了一个，这么多年了，大家在年龄上都向天马走得更近了，55555老了：）我总希望能有那么一次能够更好的聚会一次，只是由于大家忙的忙，在外地的在外地，一直未能如愿，特别是我们之中的很多同志由于一个个的走进围墙，所以机会也自然少了许多，在这里，我要说的是，不管以前发生过什么，我希望在来年的中秋，我们能够更集中更团结，让我们在一起互相聊聊这些年来的开心，快乐。痛楚，悲伤。。。。。。（哈。。估计有人要跳起来了，今年的状元玫瑰，，嘿嘿。。谁让你带一个杀手来把我们的状元拿走了，555，明年。。嘿嘿。。。你自己看着办）哇！忽然想起，明年的中秋我们又多了一个抱着小宝宝的，，玫瑰，我帮你算好了，明年如果能全部到的话，那么有24个人，哈哈，，惨了你！最后，我衷心的希望我们的友谊能像长城一样，每年的中秋都能集中！（虽然我年年拿不到状元）', NULL, '2003-09-18 15:03:00', 6, '20031020211900_bbsid_213779_board_13_761021ab67.html', '20031020211900');
